function afficherCV(t){document.getElementById("cv-nom-dash").textContent=t.name,document.getElementById("cv-taille-dash").textContent=(t.size/1024).toFixed(0)+" Ko",cvPreview.classList.add("visible"),btnUploadDash.disabled=!1}function dropCV(t){t.preventDefault();const e=t.dataTransfer.files[0];if(!e)return;const n=new DataTransfer;n.items.add(e),cvInputDash.files=n.files,afficherCV(e)}const cvInputDash=document.getElementById("cv-input-dash"),btnUploadDash=document.getElementById("btn-upload-dash"),cvPreview=document.getElementById("cv-preview-dash");cvInputDash&&cvInputDash.addEventListener("change",function(){this.files[0]&&afficherCV(this.files[0])});const photoInput=document.getElementById("photo-input-dash"),btnPhotoDash=document.getElementById("btn-photo-dash"),photoPreview=document.getElementById("photo-preview-dash");photoInput&&photoInput.addEventListener("change",function(){if(this.files[0]){const t=this.files[0];document.getElementById("photo-nom-dash").textContent=t.name,document.getElementById("photo-taille-dash").textContent=(t.size/1024).toFixed(0)+" Ko",photoPreview.classList.add("visible"),btnPhotoDash.disabled=!1}});